#include<bits/stdc++.h>
using namespace std;
int yuan[1010],yuan2[1010];
int cnt,cnt1;
int main()
{
	long long n,k,a1,a2,b1,b2;
	cin>>n>>k>>a1>>a2>>b1>>b2;
	for(int i=1;i<=n;i++){
		yuan[i-1]=i;
		yuan2[i-1]=i;
	}
	a1--;
	a2--;
	b1--;
	b2--;
	
	for(int i=0;i<k;i++){		
		reverse(&yuan[a1],&yuan[a2+1]);		
		reverse(&yuan[b1],&yuan[b2+1]);
		cnt1++;
		for(int i=0;i<n;i++)if(yuan[i]==yuan2[i])cnt++;
	//	for(int i=0;i<n;i++)cout<<yuan[i]<<" ";
		if(cnt==n)break;
		cnt=0;
	}
	for(int i=0;i<k%cnt1;i++){		
		reverse(&yuan[a1],&yuan[a2+1]);		
		reverse(&yuan[b1],&yuan[b2+1]);
	}
	for(int i=0;i<n;i++)cout<<yuan[i]<<endl;
}
